def main():
    for spec in SPECS:
        folder = BASE / spec["category"]
        folder.mkdir(parents=True, exist_ok=True)
        (folder / spec["file"]).write_text(render(spec), encoding="utf-8")

    print(f"Created {len(SPECS)} phase 5 prompt files in {BASE}")
    for category in sorted({s["category"] for s in SPECS}):
        print(f"{category}: {len(list((BASE / category).glob('*.txt')))} text files")


if __name__ == "__main__":
    main()
